from collections import deque

_review_queue: deque[ActionRecord] = deque()

async def run_agent_with_logging(
    task:        str,
    tools:       list[dict],
    tool_fns:    dict[str, Callable[..., Awaitable[Any]]],
    session_id:  str | None = None,
    max_steps:   int = 30,
) -> str:
    session_id = session_id or str(uuid.uuid4())
    messages = [{"role": "user", "content": task}]

    for step in range(max_steps):
        response = await client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(
                (b.text for b in response.content if hasattr(b, "text")), ""
            )

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue

            fn = tool_fns.get(block.name)
            if fn is None:
                result_str = json.dumps({"error": f"unknown tool: {block.name}"})
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result_str,
                })
                continue

            result, record = await dispatch_with_logging(
                session_id, block.name, block.input, fn
            )
            # Add to review queue (does not block the agent)
            _review_queue.append(record)

            result_str = json.dumps(result) if not isinstance(result, str) else result
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result_str,
            })

        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError(f"Agent exceeded max_steps={max_steps}")

from fastapi import FastAPI
from fastapi.responses import JSONResponse

app = FastAPI()

# Rollback functions: reverse each tool's effect
ROLLBACKS: dict[str, Callable] = {
    "write_file":    lambda record: restore_file(record),
    "upsert_record": lambda record: restore_record(record),
    "create_ticket": lambda record: delete_ticket(record.tool_result.get("ticket_id")),
    "delete_record": lambda record: restore_record(record),
}

async def restore_file(record: ActionRecord) -> str:
    import pathlib
    path = record.tool_input.get("path")
    if not path:
        return "no path in tool_input"
    p = pathlib.Path(path)
    if record.snapshot is None:
        p.unlink(missing_ok=True)
        return f"deleted {path} (did not exist before action)"
    p.write_text(record.snapshot)
    return f"restored {path} to pre-action content"

