@app.get("/review/queue")
async def get_review_queue(limit: int = 20):
    items = []
    for r in list(_review_queue)[:limit]:
        items.append({
            "action_id":  r.action_id,
            "session_id": r.session_id,
            "tool_name":  r.tool_name,
            "tool_input": r.tool_input,
            "status":     r.status,
            "ts":         r.ts,
        })
    return JSONResponse({"queue": items, "total": len(_review_queue)})

@app.post("/review/{action_id}/confirm")
async def confirm_action(action_id: str):
    record = _action_log.get(action_id)
    if not record:
        return JSONResponse({"error": "not found"}, status_code=404)
    record.status = ActionStatus.CONFIRMED
    return JSONResponse({"status": "confirmed"})

@app.post("/review/{action_id}/rollback")
async def rollback_action(action_id: str, reason: str = ""):
    record = _action_log.get(action_id)
    if not record:
        return JSONResponse({"error": "not found"}, status_code=404)
    if record.status == ActionStatus.ROLLED_BACK:
        return JSONResponse({"error": "already rolled back"}, status_code=400)

    rb_fn = ROLLBACKS.get(record.tool_name)
    if rb_fn is None:
        return JSONResponse({"error": f"no rollback for {record.tool_name}"}, status_code=400)

    undo_result = await rb_fn(record)
    record.status = ActionStatus.ROLLED_BACK
    record.rolled_back_at = datetime.datetime.utcnow().isoformat() + "Z"

    # Build correction context for the next agent run
    correction = (
        f"Action {record.tool_name}({json.dumps(record.tool_input)}) was rolled back by a reviewer. "
        f"Reason: {reason or 'reviewer flagged this action'}. "
        f"Undo result: {undo_result}. "
        f"Please reconsider and retry with corrected parameters."
    )
    return JSONResponse({"status": "rolled_back", "undo_result": undo_result, "correction": correction})
